<?php namespace SmartChat; class Rate_Limit { public function __construct() { add_action("rest_api_init", array($this, "check_rate_limit")); } public function check_rate_limit() { $ip = $_SERVER["REMOTE_ADDR"] ?? ""; $limit = hmsc_get_option("rate_limit", 10); $window = hmsc_get_option("rate_limit_window", 60); $key = "hmsc_rate_limit_" . md5($ip); $requests = get_transient($key) ?: 0; if ($requests >= $limit) { wp_die("Rate limit exceeded", "Rate Limit", array("response" => 429)); } set_transient($key, $requests + 1, $window); } }
